def prob_ge(weights,p):
    n=len(weights)
    pr=0.0
    for mask in range(1<<n):
        s=0; k=0
        for i,w in enumerate(weights):
            if mask>>i&1:
                s+=w; k+=1
        if s+1e-12>=p:
            pr += (p**k)*((1-p)**(n-k))
    return pr

