from itertools import combinations
def phi(weights,q):
    return prob_gt(weights,q)
def coalesce(weights,B):
    B=set(B)
    s=sum(weights[i] for i in B)
    return [w for i,w in enumerate(weights) if i not in B]+[s]
def exists_nondec_block(w,q):
    base=phi(w,q)
    n=len(w)
    best=(-1,None,None)
    for r in range(2,n+1):
        for B in combinations(range(n),r):
            val=phi(coalesce(w,B),q)
            if val-base>best[0]:
                best=(val-base,B,val)
    return best,base

