def good_length(atoms,weights,p,grid=20000):
    ts=np.linspace(0,1,grid,endpoint=False)
    vals=np.zeros(grid)
    # interval [t,t+p] mod1
    for a,w in zip(atoms,weights):
        # t such that a in [t,t+p] mod1 -> t in [a-p,a] mod1
        start=(a-p)%1; end=a%1
        if start<=end:
            vals[(ts>=start)&(ts<=end)] += w
        else:
            vals[(ts>=start)|(ts<=end)] += w
    return np.mean(vals>=p-1e-12), vals
