def dist_probs(coeff,p):
    # enumerate values for n small
    n=len(coeff)
    d=[]
    for mask in range(1<<n):
        s=0;k=0
        for i,c in enumerate(coeff):
            if mask>>i&1:
                s+=c;k+=1
        pr=p**k*(1-p)**(n-k)
        d.append((s,pr))
    return d
def two_tail_holds(coeff,p,x):
    d=dist_probs(coeff,p)
    U=sum(pr for s,pr in d if s>=x-1e-12)
    L=sum(pr for s,pr in d if s<x-1-1e-12)
    return U - (p/(1-p))*L, U,L
